source:
.card {
  padding: 13px;
  color: rgb(20, 30, 40);
}
.card:hover {
  background-color: rgb(210, 220, 230);
}
.action:focus {
  outline: 2px solid rgb(30, 90, 150);
}
.action:focus-visible {
  outline-offset: 3px;
}
.responsive {
  width: 100px;
}
@media (min-width: 700px) {
  .responsive {
    width: 200px;
  }
}
